106:   absl::StatusOr<Envoy::Http::FilterFactoryCb>
107:   createFilterFactoryFromProto(const Protobuf::Message& proto_config,
108:                                const std::string& stats_prefix,
109:                                Server::Configuration::FactoryContext& context) override {
110:     return createFilterFactoryFromProtoTyped(MessageUtil::downcastAndValidate<const ConfigProto&>(
111:                                                  proto_config, context.messageValidationVisitor()),
112:                                              stats_prefix, context);
113:   }
114:   virtual absl::StatusOr<Envoy::Http::FilterFactoryCb>
115:   createFilterFactoryFromProtoTyped(const ConfigProto& proto_config,
116:                                     const std::string& stats_prefix,
117:                                     Server::Configuration::FactoryContext& context) PURE;
