120: template <class ConfigProto, class RouteConfigProto = ConfigProto>
121: class DualFactoryBase : public CommonFactoryBase<ConfigProto, RouteConfigProto>,
122:                         public Server::Configuration::NamedHttpFilterConfigFactory,
123:                         public Server::Configuration::UpstreamHttpFilterConfigFactory {
124: public:
125:   DualFactoryBase(const std::string& name)
126:       : CommonFactoryBase<ConfigProto, RouteConfigProto>(name) {}
127: 
128:   struct DualInfo {
129:     DualInfo(Server::Configuration::UpstreamFactoryContext& context)
130:         : init_manager(context.initManager()), scope(context.scope()), is_upstream(true) {}
131:     DualInfo(Server::Configuration::FactoryContext& context)
132:         : init_manager(context.initManager()), scope(context.scope()), is_upstream(false) {}
133:     Init::Manager& init_manager;
134:     Stats::Scope& scope;
135:     bool is_upstream;
136:   };
137: 
138:   absl::StatusOr<Envoy::Http::FilterFactoryCb>
139:   createFilterFactoryFromProto(const Protobuf::Message& proto_config,
140:                                const std::string& stats_prefix,
141:                                Server::Configuration::FactoryContext& context) override {
142:     return createFilterFactoryFromProtoTyped(MessageUtil::downcastAndValidate<const ConfigProto&>(
143:                                                  proto_config, context.messageValidationVisitor()),
144:                                              stats_prefix, DualInfo(context),
145:                                              context.serverFactoryContext());
146:   }
147: 
148:   absl::StatusOr<Envoy::Http::FilterFactoryCb>
149:   createFilterFactoryFromProto(const Protobuf::Message& proto_config,
150:                                const std::string& stats_prefix,
151:                                Server::Configuration::UpstreamFactoryContext& context) override {
152:     return createFilterFactoryFromProtoTyped(
153:         MessageUtil::downcastAndValidate<const ConfigProto&>(
154:             proto_config, context.serverFactoryContext().messageValidationVisitor()),
155:         stats_prefix, DualInfo(context), context.serverFactoryContext());
156:   }
157: 
158:   virtual absl::StatusOr<Envoy::Http::FilterFactoryCb>
159:   createFilterFactoryFromProtoTyped(const ConfigProto& proto_config,
160:                                     const std::string& stats_prefix, DualInfo info,
161:                                     Server::Configuration::ServerFactoryContext& context) PURE;
162: 
163:   // This method is for dual filter to create filter from server context when it is configured
164:   // in downstream. It won't be called if a dual filter is in upstream.
165:   Envoy::Http::FilterFactoryCb createFilterFactoryFromProtoWithServerContext(
166:       const Protobuf::Message& proto_config, const std::string& stats_prefix,
167:       Server::Configuration::ServerFactoryContext& server_context) override {
168:     return createFilterFactoryFromProtoWithServerContextTyped(
169:         MessageUtil::downcastAndValidate<const ConfigProto&>(
170:             proto_config, server_context.messageValidationVisitor()),
171:         stats_prefix, server_context);
172:   }
173: 
174: private:
175:   virtual Envoy::Http::FilterFactoryCb
176:   createFilterFactoryFromProtoWithServerContextTyped(const ConfigProto&, const std::string&,
177:                                                      Server::Configuration::ServerFactoryContext&) {
178:     ExceptionUtil::throwEnvoyException(
179:         "DualFactoryBase: creating filter factory from server factory context is not supported");
180:     return nullptr;
181:   }
182: };
183: 
184: } // namespace Common
185: } // namespace HttpFilters
186: } // namespace Extensions
187: } // namespace Envoy
