282: absl::StatusOr<Network::FilterFactoryCb>
283: HttpConnectionManagerFilterConfigFactory::createFilterFactoryFromProtoAndHopByHop(
284:     const envoy::extensions::filters::network::http_connection_manager::v3::HttpConnectionManager&
285:         proto_config,
286:     Server::Configuration::FactoryContext& context, bool clear_hop_by_hop_headers) {
287:   Utility::Singletons singletons = Utility::createSingletons(context);
288: 
289:   auto filter_config = THROW_OR_RETURN_VALUE(
290:       Utility::createConfig(proto_config, context, *singletons.date_provider_,
291:                             *singletons.route_config_provider_manager_,
292:                             singletons.scoped_routes_config_provider_manager_.get(),
293:                             *singletons.tracer_manager_,
294:                             *singletons.filter_config_provider_manager_),
295:       std::shared_ptr<HttpConnectionManagerConfig>);
296: 
297:   // This lambda captures the shared_ptrs created above, thus preserving the
298:   // reference count.
299:   // Keep in mind the lambda capture list **doesn't** determine the destruction order, but it's fine
300:   // as these captured objects are also global singletons.
301:   return [singletons, filter_config, &context,
302:           clear_hop_by_hop_headers](Network::FilterManager& filter_manager) -> void {
303:     auto& server_context = context.serverFactoryContext();
304:     Server::OverloadManager& overload_manager = context.listenerInfo().shouldBypassOverloadManager()
305:                                                     ? server_context.nullOverloadManager()
306:                                                     : server_context.overloadManager();
307: 
308:     auto hcm = std::make_shared<Http::ConnectionManagerImpl>(
309:         filter_config, context.drainDecision(), server_context.api().randomGenerator(),
310:         server_context.httpContext(), server_context.runtime(), server_context.localInfo(),
311:         server_context.clusterManager(), overload_manager,
312:         server_context.mainThreadDispatcher().timeSource());
313:     if (!clear_hop_by_hop_headers) {
314:       hcm->setClearHopByHopResponseHeaders(false);
315:     }
316:     filter_manager.addReadFilter(std::move(hcm));
317:   };
318: }
