17: void FilterChainUtility::createFilterChainForFactories(
18:     Http::FilterChainManager& manager, const FilterChainOptions& options,
19:     const FilterFactoriesList& filter_factories) {
20:   bool added_missing_config_filter = false;
21:   for (const auto& filter_config_provider : filter_factories) {
22:     // If this filter is disabled explicitly, skip trying to create it.
23:     if (options.filterDisabled(filter_config_provider.provider->name())
24:             .value_or(filter_config_provider.disabled)) {
25:       continue;
26:     }
27: 
28:     auto config = filter_config_provider.provider->config();
29:     if (config.has_value()) {
30:       Filter::NamedHttpFilterFactoryCb& factory_cb = config.value().get();
31:       manager.applyFilterFactoryCb({filter_config_provider.provider->name(), factory_cb.name},
32:                                    factory_cb.factory_cb);
33:       continue;
34:     }
35: 
36:     // If a filter config is missing after warming, inject a local reply with status 500.
37:     if (!added_missing_config_filter) {
38:       ENVOY_LOG(trace, "Missing filter config for a provider {}",
39:                 filter_config_provider.provider->name());
40:       manager.applyFilterFactoryCb({}, MissingConfigFilterFactory);
41:       added_missing_config_filter = true;
42:     } else {
43:       ENVOY_LOG(trace, "Provider {} missing a filter config",
44:                 filter_config_provider.provider->name());
45:     }
46:   }
47: }
